import React, { useState, useEffect, useRef } from 'react';
import { Auth } from './components/Auth';
import { Chat } from './components/Chat';
import { DocumentStudio } from './components/DocumentStudio';
import { HumanizerView } from './components/HumanizerView';
import { Logo } from './components/Logo';
import { User, AppView, ChatSession, Message } from './types';
import { MessageSquare, FileText, LogOut, Menu, LogIn, Plus, Sparkles, Moon, Sun, RotateCcw, Search, PanelLeftClose, PanelLeft, Trash2, MoreHorizontal, Book, Zap, Code, X } from 'lucide-react';

const FREE_USAGE_LIMIT = 6;

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  const [currentView, setCurrentView] = useState<AppView>(AppView.CHAT);
  const [isSidebarOpen, setIsSidebarOpen] = useState(window.innerWidth > 768);
  const [isAuthModalOpen, setIsAuthModalOpen] = useState(false);
  const [authReason, setAuthReason] = useState<'user_action' | 'limit_reached'>('user_action');
  const [usageCount, setUsageCount] = useState(0);
  const [humanizerInitialText, setHumanizerInitialText] = useState<string>('');

  // Dark Mode State
  const [isDarkMode, setIsDarkMode] = useState(true);

  // Session Management
  const [sessions, setSessions] = useState<ChatSession[]>([]);
  const [currentSessionId, setCurrentSessionId] = useState<string | null>(null);

  // Ref to track current session ID inside async callbacks
  const currentSessionIdRef = useRef<string | null>(currentSessionId);

  // --- PERFORMANCE OPTIMIZATION: Session Cache ---
  // We use a Ref to store the full list of sessions in memory.
  // This avoids reading and JSON.parsing from localStorage on every single update.
  const allSessionsRef = useRef<ChatSession[]>([]);
  const isStorageInitialized = useRef(false);

  const persistSessions = (updatedSessions: ChatSession[]) => {
      try {
          // Write to Storage
          localStorage.setItem('iv4_chat_sessions', JSON.stringify(updatedSessions));
          // Update Memory Cache
          allSessionsRef.current = updatedSessions;
      } catch (e) {
          console.error("Failed to save sessions to localStorage", e);
      }
  };

  // Handle Dark Mode Class
  useEffect(() => {
    if (isDarkMode) {
        document.documentElement.classList.add('dark');
    } else {
        document.documentElement.classList.remove('dark');
    }
  }, [isDarkMode]);

  // Initialization & Data Loading (Runs once on mount)
  useEffect(() => {
    // 1. Initialize Session Cache from Storage
    try {
        const saved = localStorage.getItem('iv4_chat_sessions');
        if (saved) {
            allSessionsRef.current = JSON.parse(saved);
        }
    } catch (e) {
        console.error("Failed to load sessions", e);
        allSessionsRef.current = [];
    }
    isStorageInitialized.current = true;

    // 2. Restore User from LocalStorage
    const savedUser = localStorage.getItem('iv4_user');
    let loadedUser = null;
    if (savedUser) {
        try {
            loadedUser = JSON.parse(savedUser);
            setUser(loadedUser);
        } catch (e) {
            console.error("Failed to parse user from local storage");
        }
    }

    // Check usage from local storage
    const savedUsage = localStorage.getItem('iv4_usage_count');
    if (savedUsage) setUsageCount(parseInt(savedUsage));

    // Carregar sessões iniciais filtradas pelo utilizador carregado
    loadFilteredSessions(loadedUser);

    // Iniciar sempre com estado de "Nova Conversa" visualmente
    setCurrentSessionId(null);
  }, []); 

  // Função para carregar e filtrar sessões baseado no utilizador atual (Lê do Cache)
  const loadFilteredSessions = (currentUser: User | null) => {
      // Ensure we use the cache
      const allSessions = allSessionsRef.current;

      const filtered = allSessions.filter(s => {
          if (currentUser) {
              // Se logado, mostra apenas as minhas sessões
              return s.userId === currentUser.id;
          } else {
              // Se visitante, mostra apenas sessões sem userId (criadas como visitante)
              return !s.userId;
          }
      }).sort((a, b) => b.lastMessageAt - a.lastMessageAt);

      setSessions(filtered);
  };

  // Recarregar sessões sempre que o utilizador muda
  useEffect(() => {
      if (isStorageInitialized.current) {
          loadFilteredSessions(user);

          // Se a sessão atual não pertencer ao novo utilizador, resetar
          if (currentSessionId) {
              const allSessions = allSessionsRef.current;
              const session = allSessions.find(s => s.id === currentSessionId);
              if (session) {
                  const belongsToUser = user ? session.userId === user.id : !session.userId;
                  if (!belongsToUser) {
                      setCurrentSessionId(null);
                  }
              }
          }
      }
  }, [user?.id]);

  // Sync Ref with State
  useEffect(() => {
    currentSessionIdRef.current = currentSessionId;
  }, [currentSessionId]);

  // Handle window resize for responsive sidebar
  useEffect(() => {
      const handleResize = () => {
          if (window.innerWidth > 768) {
              setIsSidebarOpen(true);
          } else {
              setIsSidebarOpen(false);
          }
      };
      window.addEventListener('resize', handleResize);
      return () => window.removeEventListener('resize', handleResize);
  }, []);

  const startNewChat = () => {
      setCurrentSessionId(null);
      setCurrentView(AppView.CHAT);
      if (window.innerWidth < 768) setIsSidebarOpen(false);
  };

  const deleteSession = (e: React.MouseEvent, id: string) => {
      e.stopPropagation();

      const allSessions = allSessionsRef.current;
      const updatedAll = allSessions.filter(s => s.id !== id);

      persistSessions(updatedAll);
      loadFilteredSessions(user);

      if (currentSessionId === id) {
          setCurrentSessionId(null);
      }
  };

  const handleSessionUpdate = (messages: Message[]) => {
      const activeId = currentSessionIdRef.current;
      // Read from Memory Cache instead of LocalStorage
      const allSessions = allSessionsRef.current;
      let updatedAllSessions = [...allSessions];

      if (activeId) {
          // Update existing session
          const sessionIndex = updatedAllSessions.findIndex(s => s.id === activeId);

          if (sessionIndex !== -1) {
              // Generate Title Logic
              let newTitle = updatedAllSessions[sessionIndex].title;
              if ((newTitle === 'Nova Conversa' || !newTitle) && messages.length > 0) {
                  const firstUserMsg = messages.find(m => m.role === 'user');
                  if (firstUserMsg) {
                      newTitle = firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
                  }
              }

              updatedAllSessions[sessionIndex] = {
                  ...updatedAllSessions[sessionIndex],
                  messages,
                  title: newTitle,
                  lastMessageAt: Date.now(),
                  userId: user?.id
              };
          }
      } else {
          // Create NEW session
          const newId = Date.now().toString();
          currentSessionIdRef.current = newId; 

          let newTitle = 'Nova Conversa';
          if (messages.length > 0) {
               const firstUserMsg = messages.find(m => m.role === 'user');
               if (firstUserMsg) {
                    newTitle = firstUserMsg.text.slice(0, 30) + (firstUserMsg.text.length > 30 ? '...' : '');
               }
          }

          const newSession: ChatSession = {
              id: newId,
              title: newTitle,
              messages: messages,
              createdAt: Date.now(),
              lastMessageAt: Date.now(),
              userId: user?.id
          };

          updatedAllSessions = [newSession, ...updatedAllSessions];
          setCurrentSessionId(newId);
      }

      // Save to Storage & Cache efficiently
      persistSessions(updatedAllSessions);

      // Update local view state
      const filtered = updatedAllSessions.filter(s => {
          if (user) return s.userId === user.id;
          return !s.userId;
      }).sort((a, b) => b.lastMessageAt - a.lastMessageAt);

      setSessions(filtered);
  };

  const handleLogout = () => {
    setUser(null);
    localStorage.removeItem('iv4_user');
    setCurrentSessionId(null);
    setCurrentView(AppView.CHAT);
  };

  const handleLoginSuccess = (loggedInUser: User) => {
    // Migrate active visitor session to new user if exists
    if (currentSessionId) {
        const allSessions = allSessionsRef.current;
        const sessionIndex = allSessions.findIndex(s => s.id === currentSessionId);

        if (sessionIndex !== -1 && !allSessions[sessionIndex].userId) {
            allSessions[sessionIndex].userId = loggedInUser.id;
            persistSessions([...allSessions]);
        }
    }

    setUser(loggedInUser);
    localStorage.setItem('iv4_user', JSON.stringify(loggedInUser));
    setIsAuthModalOpen(false);
    setAuthReason('user_action');
  };

  const checkUsageLimit = (): boolean => {
    if (user) return true;

    if (usageCount >= FREE_USAGE_LIMIT) {
      setAuthReason('limit_reached');
      setIsAuthModalOpen(true);
      return false;
    }

    const newCount = usageCount + 1;
    setUsageCount(newCount);
    localStorage.setItem('iv4_usage_count', newCount.toString());
    return true;
  };

  const handleHumanizeRequest = (text: string) => {
    setHumanizerInitialText(text);
    setCurrentView(AppView.HUMANIZER);
  };

  // Buscar sessão ativa da lista filtrada
  const getCurrentSession = () => sessions.find(s => s.id === currentSessionId);

  return (
    <div className="flex h-screen bg-gray-50 dark:bg-[#030712] text-gray-900 dark:text-gray-100 font-sans overflow-hidden transition-colors duration-300">

      <Auth 
        isOpen={isAuthModalOpen} 
        onClose={() => setIsAuthModalOpen(false)} 
        onLogin={handleLoginSuccess}
        triggerReason={authReason}
      />

      {/* Sidebar - Old Interface Layout */}
      {/* Mobile Overlay Background */}
      {isSidebarOpen && window.innerWidth < 768 && (
          <div 
            className="fixed inset-0 bg-black/50 z-20"
            onClick={() => setIsSidebarOpen(false)}
          ></div>
      )}

      <aside 
        className={`fixed md:relative top-0 left-0 h-full bg-white dark:bg-[#020617] border-r border-gray-200 dark:border-white/5 transition-all duration-300 ease-in-out z-30 w-[280px] flex flex-col ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full md:w-0 md:translate-x-0 md:hidden'}`}
      >
        <div className="p-4 flex flex-col h-full relative">

            {/* Mobile Close Button */}
            <button 
                onClick={() => setIsSidebarOpen(false)}
                className="md:hidden absolute top-4 right-4 text-gray-400"
            >
                <X size={20} />
            </button>

            {/* Logo */}
            <div className="flex items-center gap-3 mb-6 px-2">
                <div className="hover:scale-105 transition-transform">
                    <Logo size={42} />
                </div>
                <span className="font-bold text-lg tracking-tight text-gray-900 dark:text-white">IV4 IA</span>
            </div>

            {/* New Chat Button */}
            <button 
                onClick={startNewChat}
                className="w-full bg-gray-100 dark:bg-[#1f2937] hover:bg-gray-200 dark:hover:bg-[#374151] text-gray-800 dark:text-white py-3 px-4 rounded-xl flex items-center gap-3 font-medium transition-colors mb-8 border border-gray-200 dark:border-white/5 shadow-sm group"
            >
                <Plus size={20} className="text-gray-500 dark:text-gray-400 group-hover:text-black dark:group-hover:text-white transition-colors" />
                Nova Conversa
            </button>

            {/* Tools Section */}
            <div className="mb-8 flex-shrink-0">
                <h3 className="text-[11px] font-bold text-gray-500 mb-2 px-3 uppercase tracking-wider">FERRAMENTAS</h3>
                <nav className="space-y-1">
                    <button 
                        onClick={() => { 
                            setCurrentView(AppView.CHAT); 
                            // When clicking Chat, ensure we clear the session to show empty state (ChatGPT style)
                            setCurrentSessionId(null);
                            if(window.innerWidth < 768) setIsSidebarOpen(false); 
                        }} 
                        className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                            currentView === AppView.CHAT 
                            ? 'bg-[#4f46e5]/10 text-[#6366f1]' 
                            : 'text-gray-600 dark:text-gray-400 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5'
                        }`}
                    >
                        <MessageSquare size={18} />
                        Chat
                    </button>
                    <button 
                        onClick={() => { setCurrentView(AppView.HUMANIZER); if(window.innerWidth < 768) setIsSidebarOpen(false); }} 
                        className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                            currentView === AppView.HUMANIZER 
                            ? 'bg-[#4f46e5]/10 text-[#6366f1]' 
                            : 'text-gray-600 dark:text-gray-400 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5'
                        }`}
                    >
                        <RotateCcw size={18} />
                        Humanizador
                    </button>
                    <button 
                        onClick={() => { setCurrentView(AppView.STUDIO); if(window.innerWidth < 768) setIsSidebarOpen(false); }} 
                        className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium transition-colors ${
                            currentView === AppView.STUDIO 
                            ? 'bg-[#4f46e5]/10 text-[#6366f1]' 
                            : 'text-gray-600 dark:text-gray-400 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5'
                        }`}
                    >
                        <FileText size={18} />
                        Estúdio
                    </button>
                </nav>
            </div>

            {/* History Section */}
            <div className="flex-grow overflow-y-auto custom-scrollbar pr-1 mb-4">
                 <h3 className="text-[11px] font-bold text-gray-500 mb-2 px-3 uppercase tracking-wider">HISTÓRICO</h3>
                 <div className="space-y-0.5">
                    {sessions.map(s => (
                        <SessionItem 
                            key={s.id} 
                            session={s} 
                            isActive={s.id === currentSessionId && currentView === AppView.CHAT} 
                            onClick={() => { 
                                setCurrentSessionId(s.id); 
                                setCurrentView(AppView.CHAT);
                                if(window.innerWidth < 768) setIsSidebarOpen(false);
                            }}
                            onDelete={(e) => deleteSession(e, s.id)}
                        />
                    ))}
                    {sessions.length === 0 && (
                        <p className="px-3 text-xs text-gray-500 italic">Sem histórico recente.</p>
                    )}
                 </div>
            </div>

            {/* Footer Actions */}
            <div className="flex-shrink-0 space-y-2 mt-auto">
                 {/* Light Mode Toggle */}
                 <button 
                    onClick={() => setIsDarkMode(!isDarkMode)}
                    className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium text-gray-600 dark:text-gray-400 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5 transition-colors"
                 >
                    {isDarkMode ? <Sun size={18} /> : <Moon size={18} />}
                    {isDarkMode ? 'Modo Claro' : 'Modo Escuro'}
                 </button>

                 <div className="pt-2 border-t border-gray-200 dark:border-white/5">
                    {user ? (
                        <div className="flex items-center gap-3 px-2 py-2 rounded-lg hover:bg-gray-100 dark:hover:bg-white/5 cursor-pointer group transition-colors">
                            <div className="w-8 h-8 rounded-full bg-[#4f46e5] text-white flex items-center justify-center font-bold text-xs">
                                {user.name.charAt(0).toUpperCase()}
                            </div>
                            <div className="flex-grow min-w-0">
                                <p className="text-sm font-medium text-gray-900 dark:text-white truncate">{user.name}</p>
                            </div>
                            <button onClick={handleLogout} className="opacity-0 group-hover:opacity-100 text-gray-400 hover:text-red-500 p-1">
                                <LogOut size={16} />
                            </button>
                        </div>
                    ) : (
                        <button 
                            onClick={() => { setAuthReason('user_action'); setIsAuthModalOpen(true); }}
                            className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm font-medium text-gray-600 dark:text-gray-400 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-white/5 transition-colors"
                        >
                            <LogIn size={18} />
                            Entrar / Inscrever-se
                        </button>
                    )}
                 </div>
            </div>
        </div>
      </aside>

      {/* Main Content Area */}
      <main className="flex-grow flex flex-col h-full relative bg-gray-50 dark:bg-[#030712] w-full transition-colors duration-300">

        {/* Mobile Header / Sidebar Toggle */}
        {!isSidebarOpen && (
             <div className="absolute top-4 left-4 z-20">
                <button 
                    onClick={() => setIsSidebarOpen(true)} 
                    className="p-2 bg-white dark:bg-[#1f2937] rounded-lg text-gray-600 dark:text-gray-300 hover:text-black dark:hover:text-white hover:bg-gray-100 dark:hover:bg-[#374151] shadow-sm"
                >
                    <PanelLeft size={20} />
                </button>
            </div>
        )}

        <div className="flex-grow h-full overflow-hidden">
            {currentView === AppView.CHAT && (
                <Chat 
                    user={user}
                    checkUsageLimit={checkUsageLimit}
                    onHumanizeRequest={handleHumanizeRequest}
                    currentSession={getCurrentSession()}
                    onUpdateSession={handleSessionUpdate}
                />
            )}
            {currentView === AppView.HUMANIZER && (
                <HumanizerView 
                    initialText={humanizerInitialText}
                    checkUsageLimit={checkUsageLimit}
                />
            )}
            {currentView === AppView.STUDIO && (
                <div className="h-full p-4 md:p-8 max-w-6xl mx-auto flex flex-col">
                        <DocumentStudio 
                            checkUsageLimit={checkUsageLimit}
                        />
                </div>
            )}
        </div>
      </main>
    </div>
  );
};

const SessionItem: React.FC<{ session: ChatSession, isActive: boolean, onClick: () => void, onDelete: (e: React.MouseEvent) => void }> = ({ session, isActive, onClick, onDelete }) => (
    <div 
        onClick={onClick}
        className={`group relative flex items-center gap-3 px-3 py-2.5 rounded-lg cursor-pointer text-sm transition-colors ${
            isActive 
            ? 'bg-gray-200 dark:bg-[#1f2937] text-gray-900 dark:text-white' 
            : 'text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-white/5 hover:text-gray-900 dark:hover:text-gray-200'
        }`}
    >
        <span className="truncate pr-6 flex-grow">{session.title}</span>

        {/* Options (Delete) */}
        <div className={`absolute right-2 top-1/2 -translate-y-1/2 ${isActive ? 'opacity-100' : 'opacity-0 group-hover:opacity-100'} transition-opacity bg-gray-200 dark:bg-[#1f2937] pl-2`}>
             <button onClick={onDelete} className="p-1 hover:text-red-500 text-gray-500 transition-colors">
                <Trash2 size={14} />
             </button>
        </div>
    </div>
);

export default App;

import { GoogleGenAI } from "@google/genai";
import { HumanizerVariant } from "../types";

// Função auxiliar para obter o cliente de forma segura
const getAiClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API_KEY_MISSING");
  }
  return new GoogleGenAI({ apiKey });
};

// Função auxiliar para esperar (delay)
const wait = (ms: number) => new Promise(resolve => setTimeout(resolve, ms));

/**
 * Traduz erros técnicos para mensagens amigáveis ao utilizador (PT-MZ/PT-PT)
 */
const getFriendlyErrorMessage = (error: any): string => {
    const msg = error.message || error.toString();

    if (msg.includes("API_KEY_MISSING")) return "Chave de API não configurada. Contacte o administrador.";
    if (msg.includes("429") || msg.includes("Quota exceeded") || msg.includes("RESOURCE_EXHAUSTED")) {
        return "⚠️ O sistema está com muito tráfego (Limite de Quota). Por favor, aguarde 1 minuto e tente novamente.";
    }
    if (msg.includes("503") || msg.includes("Overloaded")) {
        return "⚠️ Os servidores da Google estão sobrecarregados. Tente novamente em breve.";
    }
    if (msg.includes("fetch failed") || msg.includes("NetworkError") || msg.includes("Failed to fetch")) {
        return "⚠️ Erro de conexão. Verifique a sua ligação à internet.";
    }
    if (msg.includes("SAFETY") || msg.includes("blocked")) {
        return "⚠️ A resposta foi bloqueada pelos filtros de segurança (Conteúdo sensível). Tente reformular a sua pergunta.";
    }
    if (msg.includes("400") || msg.includes("INVALID_ARGUMENT")) {
        return "⚠️ O pedido foi rejeitado. O texto ou ficheiro pode ser demasiado grande ou inválido.";
    }

    return "⚠️ Ocorreu um erro inesperado ao comunicar com a IA.";
};

// Wrapper genérico para Retry com Feedback Inteligente
async function withRetry<T>(
    operation: () => Promise<T>, 
    onStatusUpdate?: (msg: string) => void,
    retries = 3, // Reduzido para evitar esperas longas na UI
    initialDelay = 2000
): Promise<T> {
    let lastError: any;

    for (let i = 0; i < retries; i++) {
        try {
            return await operation();
        } catch (error: any) {
            lastError = error;
            const errorMsg = error.message || error.toString();

            // Não faz retry para erros fatais (Auth, Bad Request, Safety)
            if (errorMsg.includes("API_KEY") || errorMsg.includes("400") || errorMsg.includes("SAFETY")) {
                throw error;
            }

            const isRateLimit = errorMsg.includes('429') || errorMsg.includes('Quota') || errorMsg.includes('RESOURCE');
            const isServerOverload = errorMsg.includes('503');
            const isNetworkError = errorMsg.includes('fetch failed');

            if (isRateLimit || isServerOverload || isNetworkError) {
                if (i === retries - 1) break;

                let waitTime = initialDelay * Math.pow(2, i);

                // Feedback visual se fornecido
                if (onStatusUpdate) {
                    const friendly = getFriendlyErrorMessage(error);
                    onStatusUpdate(`\n\n_${friendly} Tentando novamente (${i+1}/${retries})..._`);
                }

                console.log(`[IV4 IA] Retry ${i+1}/${retries} após erro: ${errorMsg}`);
                await wait(waitTime);
                continue;
            }

            throw error;
        }
    }
    throw lastError;
}

export const GeminiService = {
  /**
   * Chat com a IA com suporte a streaming, Thinking Mode e Google Search dinâmicos.
   */
  async chatStream(
      history: { role: string; parts: { text?: string; inlineData?: any }[] }[], 
      message: string, 
      onChunk: (text: string) => void,
      mediaBase64?: string, 
      mediaType?: string, 
      signal?: AbortSignal,
      config?: { isThinking?: boolean; isSearch?: boolean }
  ): Promise<void> {
    let hasReceivedContent = false;

    try {
      const ai = getAiClient();

      const now = new Date();
      const options: Intl.DateTimeFormatOptions = { 
        weekday: 'long', year: 'numeric', month: 'long', day: 'numeric',
        hour: '2-digit', minute: '2-digit'
      };
      const currentFullDate = now.toLocaleDateString('pt-PT', options);

      const systemInstruction = `
        Você é o IV4 IA, um assistente de inteligência artificial avançado.

        == CONTEXTO ==
        HOJE: ${currentFullDate}.
        LOCAL: Moçambique.
        CRIADOR: Ivo Nunes Jaime (Lichinga, Niassa).

        == DIRETRIZES ==
        - Seja útil, académico e educado.
        - Idioma: Português (Moçambique).
        - ${config?.isSearch ? 'Use Google Search se necessário.' : 'Use seu conhecimento interno.'}
      `;

      // Configuração de Tools
      const tools: any[] = [];
      if (config?.isSearch) tools.push({ googleSearch: {} });

      const modelConfig: any = {
        systemInstruction: systemInstruction,
      };

      if (tools.length > 0) modelConfig.tools = tools;

      if (config?.isThinking) {
        modelConfig.thinkingConfig = { thinkingBudget: 16384 }; 
      }

      const chat = ai.chats.create({
        model: 'gemini-2.5-flash',
        history: history,
        config: modelConfig
      });

      await withRetry(async () => {
          let responseStream;

          if (mediaBase64 && mediaType) {
            const base64Data = mediaBase64.includes(',') ? mediaBase64.split(',')[1] : mediaBase64;
            responseStream = await chat.sendMessageStream({
                message: [
                    { text: message },
                    { inlineData: { data: base64Data, mimeType: mediaType } }
                ]
            });
          } else {
            responseStream = await chat.sendMessageStream({ message: message });
          }

          for await (const chunk of responseStream) {
            if (signal?.aborted) break;
            const text = chunk.text;
            if (text) {
                hasReceivedContent = true;
                onChunk(text);
            }
          }
      }, (statusMsg) => {
          // Apenas mostra mensagens de "Tentando novamente" se já recebemos algo, 
          // caso contrário a UI lida com o erro inicial
          if (hasReceivedContent) onChunk(statusMsg);
      });

    } catch (error: any) {
      console.error("Chat Stream Error:", error);

      const friendlyMsg = getFriendlyErrorMessage(error);

      if (!hasReceivedContent) {
          // Se falhou antes de enviar qualquer coisa, lançamos o erro para a UI tratar (ex: remover mensagem vazia)
          throw new Error(friendlyMsg);
      } else {
          // Se falhou no meio do stream, anexamos o erro ao final da mensagem existente
          onChunk(`\n\n---\n**Erro:** ${friendlyMsg}`);
      }
    }
  },

  async chat(
      history: { role: string; parts: { text?: string; inlineData?: any }[] }[], 
      message: string, 
      mediaBase64?: string, 
      mediaType?: string, 
      signal?: AbortSignal
  ): Promise<string> {
    let fullText = "";
    try {
        await this.chatStream(
            history, 
            message, 
            (chunk) => { fullText += chunk; }, 
            mediaBase64, 
            mediaType, 
            signal
        );
        return fullText;
    } catch (e: any) {
        throw e; // Repassa erro tratado
    }
  },

  async negotiateDocumentDetails(history: { role: string; text: string }[], currentMessage: string): Promise<{ 
      reply: string; extractedData: any; isReady: boolean 
  }> {
    return withRetry(async () => {
        try {
            const ai = getAiClient();
            const prompt = `
                Objetivo: Extrair dados para gerar documento (Contexto: Moçambique).
                Histórico: ${JSON.stringify(history)}
                Nova Msg: "${currentMessage}"

                Extraia JSON: { "reply": "...", "extractedData": {...}, "isReady": boolean }
                Tipos: TRABALHO_ESCOLAR, RELATORIO, CURRICULO, CARTA.
                Dados necessários: Escola, Aluno(s), Tema, Classe, Cidade.
            `;

            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt,
                config: { responseMimeType: 'application/json' }
            });

            return JSON.parse(response.text || "{}");
        } catch (error: any) {
             throw new Error(getFriendlyErrorMessage(error));
        }
    });
  },

  async editDocumentFragment(currentHTML: string, userInstruction: string): Promise<string> {
    return withRetry(async () => {
        const ai = getAiClient();
        try {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: `Edite este HTML seguindo a instrução: "${userInstruction}".\nHTML: ${currentHTML}`
            });
            return (response.text || currentHTML).replace(/```html/g, '').replace(/```/g, '');
        } catch (error: any) {
            throw new Error(getFriendlyErrorMessage(error));
        }
    });
  },

  async generateDocument(data: any, addBorder: boolean = true): Promise<string> {
    return withRetry(async () => {
        const ai = getAiClient();
        const prompt = `
            Crie um documento HTML Académico Completo (Moçambique).
            Dados: ${JSON.stringify(data)}.
            ESTRUTURA:
            1. Capa (Div .page com .page-border)
            2. Contra-capa (Div .page com avaliação)
            3. Índice
            4. Conteúdo (Introdução, Desenvolvimento, Conclusão, Bibliografia).

            Use CSS Times New Roman, paginas A4 (21cm x 29.7cm).
            Retorne APENAS HTML.
        `;

        try {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: prompt
            });
            return (response.text || "").replace(/```html/g, '').replace(/```/g, '');
        } catch (error: any) {
            throw new Error(getFriendlyErrorMessage(error));
        }
    });
  },

  async humanizeText(text: string, variant: HumanizerVariant): Promise<string> {
    return withRetry(async () => {
        const ai = getAiClient();
        try {
            const response = await ai.models.generateContent({
                model: 'gemini-2.5-flash',
                contents: `Reescreva como falante nativo de ${variant}: "${text}"`
            });
            return response.text || text;
        } catch (error: any) {
             throw new Error(getFriendlyErrorMessage(error));
        }
    });
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Send, Image as ImageIcon, Code, Zap, Sparkles, Paperclip, X, FileText, Square, Copy, Check, Globe, BrainCircuit, ArrowUp, Plus, Book, Lightbulb, GraduationCap, AlertTriangle } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Message, User, ChatSession } from '../types';
import { Logo } from './Logo';

interface ChatProps {
    user: User | null;
    checkUsageLimit: () => boolean;
    onHumanizeRequest: (text: string) => void;
    currentSession?: ChatSession;
    onUpdateSession: (messages: Message[]) => void;
}

const CodeBlock: React.FC<{ code: string, language: string }> = ({ code, language }) => {
    const [copied, setCopied] = useState(false);

    const handleCopy = () => {
        navigator.clipboard.writeText(code);
        setCopied(true);
        setTimeout(() => setCopied(false), 2000);
    };

    return (
        <div className="my-4 rounded-lg overflow-hidden border border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-[#0d1117] text-gray-800 dark:text-gray-100 font-mono text-sm shadow-sm">
            <div className="flex items-center justify-between px-4 py-2 bg-gray-100 dark:bg-[#161b22] border-b border-gray-200 dark:border-gray-700">
                <span className="text-xs text-gray-500 dark:text-gray-400 font-semibold uppercase">{language || 'code'}</span>
                <button 
                    onClick={handleCopy} 
                    className="flex items-center gap-1.5 text-xs text-gray-500 dark:text-gray-400 hover:text-indigo-600 dark:hover:text-white transition-colors"
                >
                    {copied ? <Check size={14} className="text-green-500" /> : <Copy size={14} />}
                    {copied ? 'Copiado!' : 'Copiar'}
                </button>
            </div>
            <div className="p-4 overflow-x-auto custom-scrollbar bg-white dark:bg-[#0d1117]">
                <pre><code>{code}</code></pre>
            </div>
        </div>
    );
};

export const Chat: React.FC<ChatProps> = ({ user, checkUsageLimit, onHumanizeRequest, currentSession, onUpdateSession }) => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [selectedMedia, setSelectedMedia] = useState<{data: string, type: string, name: string} | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [isStreaming, setIsStreaming] = useState(false);

  // Toggles
  const [isThinkingEnabled, setIsThinkingEnabled] = useState(false);
  const [isSearchEnabled, setIsSearchEnabled] = useState(false);

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);
  const abortControllerRef = useRef<AbortController | null>(null);

  useEffect(() => {
      if (currentSession) {
          setMessages(currentSession.messages);
      } else {
          setMessages([]);
      }
  }, [currentSession?.id]);

  useEffect(() => {
    scrollToBottom();
  }, [messages, isStreaming]); // Scroll quando mensagens mudam ou quando o streaming atualiza

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  const handleFileSelect = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setSelectedMedia({
            data: reader.result as string,
            type: file.type,
            name: file.name
        });
      };
      reader.readAsDataURL(file);
    }
  };

  const handleStop = () => {
      if (abortControllerRef.current) {
          abortControllerRef.current.abort();
          abortControllerRef.current = null;
          setIsLoading(false);
          setIsStreaming(false);

          // Adiciona mensagem de cancelado se necessário ou apenas para o estado atual
          setMessages(prev => {
              const lastMsg = prev[prev.length - 1];
              if (lastMsg.role === 'model' && lastMsg.text === '') {
                  // Se cancelou antes de vir qualquer texto
                   return [...prev.slice(0, -1), {
                      ...lastMsg,
                      text: "⏹️ Resposta cancelada."
                   }];
              }
              return prev;
          });
      }
  };

  const handleSend = async (textOverride?: string) => {
    const textToSend = textOverride || input;
    if ((!textToSend.trim() && !selectedMedia) || isLoading) return;

    if (!checkUsageLimit()) return;

    const userMsg: Message = {
      id: Date.now().toString(),
      role: 'user',
      text: textToSend,
      image: selectedMedia?.data || undefined, 
      timestamp: Date.now(),
    };

    // Atualiza estado local e UI
    const newMessages = [...messages, userMsg];
    setMessages(newMessages);
    onUpdateSession(newMessages);

    setInput('');
    const mediaToSend = selectedMedia; 
    setSelectedMedia(null); 
    setIsLoading(true);
    setIsStreaming(false);

    abortControllerRef.current = new AbortController();

    // ID para a nova mensagem do bot
    const botMsgId = (Date.now() + 1).toString();
    let accumulatedText = "";

    try {
      const history = messages
        .filter(m => !m.image) 
        .map(m => ({
            role: m.role,
            parts: [{ text: m.text }]
        }));

      const config = {
          isThinking: isThinkingEnabled,
          isSearch: isSearchEnabled
      };

      await GeminiService.chatStream(
          history, 
          userMsg.text, 
          (chunkText) => {
              setIsStreaming(true);

              setMessages(prev => {
                  const lastMsg = prev[prev.length - 1];

                  if (lastMsg && lastMsg.id === botMsgId) {
                      return prev.map(m => 
                          m.id === botMsgId ? { ...m, text: m.text + chunkText } : m
                      );
                  } else {
                      return [...prev, {
                          id: botMsgId,
                          role: 'model',
                          text: chunkText,
                          timestamp: Date.now()
                      }];
                  }
              });

              accumulatedText += chunkText;
          },
          mediaToSend?.data,
          mediaToSend?.type,
          abortControllerRef.current.signal,
          config 
      );

      if (accumulatedText) {
        const finalMessages = [...newMessages, {
            id: botMsgId,
            role: 'model' as const,
            text: accumulatedText,
            timestamp: Date.now()
        }];
        onUpdateSession(finalMessages);
      }

    } catch (error: any) {
        if (error.name !== 'AbortError' && error.message !== 'Aborted') {
            const errorText = error.message || "Ocorreu um erro inesperado.";

            const errorMsg: Message = {
                id: (Date.now() + 1).toString(),
                role: 'model',
                text: errorText, // O serviço já retorna mensagens amigáveis
                timestamp: Date.now(),
            };
            const failedMessages = [...newMessages, errorMsg];
            setMessages(failedMessages);
            onUpdateSession(failedMessages);
        }
    } finally {
      setIsLoading(false);
      setIsStreaming(false);
      abortControllerRef.current = null;
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const renderMessageContent = (text: string) => {
    const parts = text.split(/```(\w*)\n([\s\S]*?)```/g);

    return parts.map((part, index) => {
        if (index % 3 === 0) {
            if (!part.trim()) return null;
            // Detecção básica de erro para estilização
            if (part.startsWith('⚠️') || part.includes('Erro:')) {
                return (
                    <div key={index} className="whitespace-pre-wrap leading-relaxed text-red-600 dark:text-red-400 font-medium bg-red-50 dark:bg-red-900/10 p-2 rounded-lg border border-red-100 dark:border-red-800/30">
                        {part}
                    </div>
                );
            }
            return <div key={index} className="whitespace-pre-wrap leading-relaxed text-gray-800 dark:text-gray-200">{part}</div>;
        }
        if (index % 3 === 1) return null;
        const language = parts[index - 1];
        return <CodeBlock key={index} code={part} language={language} />;
    });
  };

  const quickActions = [
    { icon: Book, text: "Resuma a Revolução Industrial" },
    { icon: Zap, text: "Explique Física Quântica simples" },
    { icon: Code, text: "Crie um script Python básico" },
    { icon: Sparkles, text: "Ideias para um projeto de História" },
  ];

  if (messages.length === 0) {
    return (
        <div className="flex flex-col h-full bg-gray-50 dark:bg-[#030712] text-gray-900 dark:text-white overflow-hidden relative transition-colors duration-300">
            <div className="flex-grow flex flex-col items-center justify-center px-4 w-full max-w-2xl mx-auto z-10 pb-20">
                <div className="mb-8 hover:scale-105 transition-transform duration-300">
                    <Logo size={72} />
                </div>

                <h1 className="text-3xl font-bold text-gray-900 dark:text-white mb-8 text-center tracking-tight">
                    Como posso ajudar?
                </h1>

                <InputArea 
                    input={input} 
                    setInput={setInput} 
                    handleSend={handleSend} 
                    handleKeyDown={handleKeyDown} 
                    isLoading={isLoading} 
                    handleStop={handleStop}
                    handleFileSelect={handleFileSelect}
                    selectedMedia={selectedMedia}
                    setSelectedMedia={setSelectedMedia}
                    fileInputRef={fileInputRef}
                    isThinkingEnabled={isThinkingEnabled}
                    setIsThinkingEnabled={setIsThinkingEnabled}
                    isSearchEnabled={isSearchEnabled}
                    setIsSearchEnabled={setIsSearchEnabled}
                    className="w-full relative mb-10"
                    placeholder="Pergunte qualquer coisa..."
                    isCentered={true}
                />

                <div className="grid grid-cols-1 md:grid-cols-2 gap-3 w-full">
                    {quickActions.map((action, i) => (
                        <button 
                            key={i}
                            onClick={() => handleSend(action.text)} 
                            className="flex items-center gap-3 px-5 py-4 bg-white dark:bg-[#1f2937]/40 hover:bg-gray-100 dark:hover:bg-[#374151] border border-gray-200 dark:border-white/5 hover:border-indigo-300 dark:hover:border-white/10 rounded-2xl transition-all text-left group shadow-sm dark:shadow-none"
                        >
                            <div className="text-gray-500 dark:text-gray-400 group-hover:text-indigo-600 dark:group-hover:text-white transition-colors">
                                <action.icon size={20} />
                            </div>
                            <span className="text-sm text-gray-700 dark:text-gray-300 font-medium group-hover:text-indigo-700 dark:group-hover:text-white transition-colors">{action.text}</span>
                        </button>
                    ))}
                </div>
            </div>
        </div>
    );
  }

  return (
    <div className="flex flex-col h-full bg-gray-50 dark:bg-[#030712] text-gray-900 dark:text-white transition-colors duration-300">
      <div className="flex-grow overflow-y-auto px-4 md:px-0 scroll-smooth pb-36">
        <div className="max-w-3xl mx-auto py-6 space-y-8">
          {messages.map((msg) => (
            <div key={msg.id} className="flex flex-col gap-2">
                {msg.role === 'user' && (
                    <div className="flex justify-end">
                        <div className="bg-white dark:bg-[#1f2937] px-5 py-3 rounded-2xl rounded-tr-none text-gray-800 dark:text-gray-100 max-w-[85%] leading-relaxed border border-gray-200 dark:border-white/5 shadow-sm">
                             {msg.image && (
                                <img src={msg.image} alt="Upload" className="max-h-48 rounded-lg mb-2" />
                             )}
                             {msg.text}
                        </div>
                    </div>
                )}

                {msg.role === 'model' && (
                    <div className="flex gap-4">
                        <div className="shrink-0 mt-1">
                            <Logo size={32} />
                        </div>
                        <div className="flex-grow min-w-0 pt-1">
                            <div className="text-gray-800 dark:text-gray-200 text-base leading-relaxed">
                                {renderMessageContent(msg.text)}
                                {isStreaming && msg.id === messages[messages.length-1].id && (
                                    <span className="inline-block w-2 h-4 align-middle bg-indigo-500 ml-1 animate-pulse rounded-sm"></span>
                                )}
                            </div>
                            {(!isStreaming || msg.text.length > 50) && (
                                <div className="flex items-center gap-4 mt-2 fade-in">
                                    <button onClick={() => onHumanizeRequest(msg.text)} className="p-1 text-gray-400 hover:text-[#4f46e5] dark:text-gray-500 dark:hover:text-[#a78bfa] transition-colors" title="Humanizar">
                                        <Zap size={16} />
                                    </button>
                                    <button onClick={() => navigator.clipboard.writeText(msg.text)} className="p-1 text-gray-400 hover:text-black dark:text-gray-500 dark:hover:text-white transition-colors" title="Copiar">
                                        <Copy size={16} />
                                    </button>
                                </div>
                            )}
                        </div>
                    </div>
                )}
            </div>
          ))}

          {isLoading && !isStreaming && (
            <div className="flex gap-4">
               <div className="shrink-0 mt-1 animate-pulse">
                   <Logo size={32} />
               </div>
               <div className="flex flex-col justify-center mt-2">
                   {isThinkingEnabled ? (
                       <span className="text-xs font-medium text-indigo-600 dark:text-indigo-400 animate-pulse flex items-center gap-2">
                          <BrainCircuit size={14} />
                          A analisar e raciocinar...
                       </span>
                   ) : (
                       <div className="flex items-center gap-1">
                           <span className="w-1.5 h-1.5 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce"></span>
                           <span className="w-1.5 h-1.5 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce delay-100"></span>
                           <span className="w-1.5 h-1.5 bg-gray-400 dark:bg-gray-500 rounded-full animate-bounce delay-200"></span>
                       </div>
                   )}
               </div>
            </div>
          )}
          <div ref={messagesEndRef} className="h-4" />
        </div>
      </div>

      <InputArea 
            input={input} 
            setInput={setInput} 
            handleSend={handleSend} 
            handleKeyDown={handleKeyDown} 
            isLoading={isLoading} 
            handleStop={handleStop}
            handleFileSelect={handleFileSelect}
            selectedMedia={selectedMedia}
            setSelectedMedia={setSelectedMedia}
            fileInputRef={fileInputRef}
            isThinkingEnabled={isThinkingEnabled}
            setIsThinkingEnabled={setIsThinkingEnabled}
            isSearchEnabled={isSearchEnabled}
            setIsSearchEnabled={setIsSearchEnabled}
            className="fixed bottom-0 left-0 md:left-0 lg:left-0 right-0 bg-gray-50 dark:bg-[#030712] pt-4 pb-6 px-4 z-20 flex justify-center transition-colors duration-300" 
        />
    </div>
  );
};

// Reusable Input Component
const InputArea = ({ 
    input, setInput, handleSend, handleKeyDown, isLoading, handleStop, 
    handleFileSelect, selectedMedia, setSelectedMedia, fileInputRef,
    isThinkingEnabled, setIsThinkingEnabled, isSearchEnabled, setIsSearchEnabled,
    className, placeholder, isCentered
}: any) => {
    return (
        <div className={className}>
            <div className={`max-w-3xl w-full ${!isCentered ? 'md:ml-[280px] md:mr-0 transition-all duration-300' : ''}`}> 
                <div className={`bg-white dark:bg-[#1f2937] rounded-2xl p-2 border border-gray-200 dark:border-white/5 shadow-xl dark:shadow-2xl relative flex flex-col transition-all focus-within:border-indigo-500/50 dark:focus-within:border-white/10 ${isCentered ? 'min-h-[60px]' : ''}`}>

                    {selectedMedia && (
                        <div className="mx-2 mt-2 mb-1 p-2 bg-gray-100 dark:bg-[#374151] rounded-lg inline-flex items-center gap-2 self-start border border-gray-200 dark:border-transparent">
                            {selectedMedia.type.includes('image') ? 
                                <img src={selectedMedia.data} className="h-8 w-8 rounded object-cover" /> : 
                                <FileText size={20} className="text-gray-600 dark:text-white"/>}
                            <span className="text-xs text-gray-700 dark:text-gray-300 truncate max-w-[150px]">{selectedMedia.name}</span>
                            <button onClick={() => setSelectedMedia(null)}><X size={14} className="text-gray-400 hover:text-red-500 dark:hover:text-white" /></button>
                        </div>
                    )}

                    <div className="flex items-center gap-2 px-2 pb-2">
                        <button 
                            onClick={() => setIsThinkingEnabled(!isThinkingEnabled)}
                            className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-xs font-medium transition-colors ${isThinkingEnabled ? 'bg-indigo-100 text-indigo-700 dark:bg-indigo-900/30 dark:text-indigo-300 ring-1 ring-indigo-500/30' : 'text-gray-500 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-800 border border-transparent'}`}
                            title="Ativar Raciocínio (Thinking Mode) para respostas mais complexas"
                        >
                            <BrainCircuit size={14} className={isThinkingEnabled ? "animate-pulse" : ""} />
                            Raciocínio {isThinkingEnabled ? 'On' : 'Off'}
                        </button>
                         <button 
                            onClick={() => setIsSearchEnabled(!isSearchEnabled)}
                            className={`flex items-center gap-1.5 px-2 py-1 rounded-md text-xs font-medium transition-colors ${isSearchEnabled ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-300' : 'text-gray-500 hover:bg-gray-100 dark:text-gray-400 dark:hover:bg-gray-800'}`}
                        >
                            <Globe size={14} />
                            Pesquisa {isSearchEnabled ? 'On' : 'Off'}
                        </button>
                    </div>

                    <div className="flex items-center w-full">
                         <textarea
                            value={input}
                            onChange={(e) => setInput(e.target.value)}
                            onKeyDown={handleKeyDown}
                            placeholder={placeholder || "Pergunte qualquer coisa..."}
                            className="flex-grow bg-transparent border-none text-gray-900 dark:text-white placeholder-gray-400 dark:placeholder-gray-500 px-4 py-3 focus:ring-0 resize-none min-h-[50px] max-h-[200px] outline-none"
                            rows={1}
                            style={{ height: 'auto', overflowY: 'hidden' }}
                        />

                         <input 
                                type="file" 
                                ref={fileInputRef} 
                                onChange={handleFileSelect} 
                                className="hidden" 
                            />
                        <button onClick={() => fileInputRef.current?.click()} className="p-2 text-gray-400 hover:text-indigo-600 dark:hover:text-white transition-colors mr-1">
                             <Paperclip size={20} />
                        </button>

                        {isLoading ? (
                            <button onClick={handleStop} className="p-2 mr-2 rounded-lg bg-gray-200 dark:bg-white text-black hover:opacity-90">
                                <Square size={16} fill="currentColor" />
                            </button>
                        ) : (
                            <button 
                                onClick={() => handleSend()} 
                                disabled={!input.trim() && !selectedMedia}
                                className="p-2 mr-2 rounded-lg bg-gray-100 dark:bg-[#374151] text-gray-400 dark:text-gray-400 hover:text-indigo-600 dark:hover:text-white hover:bg-gray-200 dark:hover:bg-[#4b5563] disabled:opacity-30 disabled:cursor-not-allowed transition-colors"
                            >
                                <Send size={20} />
                            </button>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
}

import React, { useState, useRef, useEffect } from 'react';
import { Sparkles, Send, X, ArrowLeft, Download, FileCheck, CheckCircle, Loader2, Edit3, Save, Layers, Book, Briefcase, FileText, Mail, FileType, Bold, Italic, Underline, AlignLeft, AlignCenter, AlignRight, AlignJustify, List, ListOrdered, Indent, Outdent, BoxSelect, FolderOpen, Image as ImageIcon, Frame, PlusCircle, Check, AlertTriangle } from 'lucide-react';
import { GeminiService } from '../services/geminiService';
import { Humanizer } from './Humanizer';
import { SavedDocument } from '../types';

interface DocumentStudioProps {
    checkUsageLimit: () => boolean;
}

interface StudioMessage {
    id: string;
    role: 'user' | 'assistant' | 'system';
    text: string;
}

// Ribbon Tabs
type RibbonTab = 'inicio' | 'inserir' | 'layout';

export const DocumentStudio: React.FC<DocumentStudioProps> = ({ checkUsageLimit }) => {
  // Modes: 'wizard' (chatting details) | 'preview' (generated doc)
  const [mode, setMode] = useState<'wizard' | 'preview'>('wizard');
  const [activeTab, setActiveTab] = useState<RibbonTab>('inicio');

  // Chat State
  const [input, setInput] = useState('');
  const [messages, setMessages] = useState<StudioMessage[]>([]);
  const [isTyping, setIsTyping] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Error UI State
  const [errorMsg, setErrorMsg] = useState<string | null>(null);

  // Metadata State
  const [metadata, setMetadata] = useState<any>({});
  const [isReadyToGenerate, setIsReadyToGenerate] = useState(false);

  // Preview / Editor State
  const [documentContent, setDocumentContent] = useState<string>('');
  const [showHumanizer, setShowHumanizer] = useState(false);
  const [isGeneratingDoc, setIsGeneratingDoc] = useState(false);
  const editorRef = useRef<HTMLDivElement>(null);

  // AI Edit State
  const [showAIEditModal, setShowAIEditModal] = useState(false);
  const [aiEditPrompt, setAiEditPrompt] = useState('');
  const [isAIEditing, setIsAIEditing] = useState(false);

  // Persistence State
  const [savedDocuments, setSavedDocuments] = useState<SavedDocument[]>([]);
  const [showSavedDocsModal, setShowSavedDocsModal] = useState(false);

  // Initial Greeting & Load Saved Docs
  useEffect(() => {
    if (messages.length === 0) {
        setMessages([{
            id: 'init',
            role: 'assistant',
            text: 'Olá! Sou o Criador de Documentos do IV4. O que deseja criar hoje? (Ex: "Um trabalho de História em grupo", "Uma carta de pedido de emprego").'
        }]);
    }
    const saved = localStorage.getItem('iv4_saved_docs');
    if (saved) {
        try {
            setSavedDocuments(JSON.parse(saved));
        } catch(e) { console.error(e); }
    }
  }, []);

  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // --- PERSISTENCE ---
  const saveDocument = () => {
      if (!documentContent) return;

      const title = metadata.topic || metadata.subject || `Documento ${new Date().toLocaleDateString()}`;
      const newDoc: SavedDocument = {
          id: Date.now().toString(),
          title: title,
          content: documentContent,
          createdAt: Date.now(),
          metadata: metadata
      };

      const updatedDocs = [newDoc, ...savedDocuments];
      setSavedDocuments(updatedDocs);
      localStorage.setItem('iv4_saved_docs', JSON.stringify(updatedDocs));
      // Toast feedback could be added here
  };

  const loadDocument = (doc: SavedDocument) => {
      setMetadata(doc.metadata || {});
      setDocumentContent(doc.content);
      setMode('preview');
      setShowSavedDocsModal(false);
      // Wait for render to update innerHTML ref if needed
      setTimeout(() => {
          if (editorRef.current) editorRef.current.innerHTML = doc.content;
      }, 100);
  };

  const deleteSavedDocument = (id: string, e: React.MouseEvent) => {
      e.stopPropagation();
      const updated = savedDocuments.filter(d => d.id !== id);
      setSavedDocuments(updated);
      localStorage.setItem('iv4_saved_docs', JSON.stringify(updated));
  };

  // --- CHAT LOGIC ---
  const handleSendMessage = async () => {
    if (!input.trim() || isTyping) return;
    if (!checkUsageLimit()) return;

    setErrorMsg(null); // Clear previous errors
    const userText = input;
    const userMsg: StudioMessage = { id: Date.now().toString(), role: 'user', text: userText };

    setMessages(prev => [...prev, userMsg]);
    setInput('');
    setIsTyping(true);

    try {
        const history = messages.filter(m => m.role !== 'system').map(m => ({ role: m.role === 'user' ? 'user' : 'model', text: m.text }));
        const result = await GeminiService.negotiateDocumentDetails(history, userText);

        setMetadata((prev: any) => ({ ...prev, ...result.extractedData }));
        setIsReadyToGenerate(result.isReady);

        const aiMsg: StudioMessage = { 
            id: (Date.now() + 1).toString(), 
            role: 'assistant', 
            text: result.reply 
        };
        setMessages(prev => [...prev, aiMsg]);

    } catch (error: any) {
        // Exibir erro amigável no chat como mensagem de sistema
        const sysMsg: StudioMessage = {
            id: Date.now().toString(),
            role: 'system',
            text: `⚠️ ${error.message || "Ocorreu um erro ao processar. Tente novamente."}`
        };
        setMessages(prev => [...prev, sysMsg]);
    } finally {
        setIsTyping(false);
    }
  };

  const handleGenerateDocument = async () => {
    setIsGeneratingDoc(true);
    setErrorMsg(null);
    try {
        const content = await GeminiService.generateDocument(metadata, true);
        setDocumentContent(content);
        setMode('preview');
    } catch (e: any) {
        setErrorMsg(e.message || "Não foi possível gerar o documento. Tente novamente.");
    } finally {
        setIsGeneratingDoc(false);
    }
  };

  // --- EDITOR COMMANDS ---
  const executeCommand = (command: string, value: string | undefined = undefined) => {
    document.execCommand(command, false, value);
    if (editorRef.current) {
        editorRef.current.focus();
    }
  };

  const handleDownloadPDF = () => {
    // 1. Create a hidden iframe
    const iframe = document.createElement('iframe');
    iframe.style.position = 'absolute';
    iframe.style.width = '0';
    iframe.style.height = '0';
    iframe.style.border = '0';
    iframe.style.visibility = 'hidden';
    document.body.appendChild(iframe);

    // 2. Write content to iframe
    const doc = iframe.contentWindow?.document;
    if (doc) {
        doc.open();
        doc.write(`
            <!DOCTYPE html>
            <html>
            <head>
                <title>${metadata.topic || "Documento"}</title>
                <style>
                    /* Basic Print Reset */
                    @page { margin: 0; size: auto; }
                    body { 
                        margin: 0; 
                        padding: 0; 
                        font-family: 'Times New Roman', serif; 
                        background: white;
                        -webkit-print-color-adjust: exact;
                    }

                    /* Ensure content container uses full width */
                    .iv4-document-container {
                        width: 100%;
                    }

                    /* Hide Editor UI elements */
                    .drag-handle, .iv4-ui-element { display: none !important; }

                    /* Page Break Logic */
                    .page {
                        page-break-after: always;
                        break-after: page;
                        width: 100%;
                        min-height: 29.7cm; 
                        position: relative;
                        overflow: hidden;
                        margin: 0;
                        box-shadow: none;
                    }

                    /* Override any generated "visibility: hidden" from Gemini CSS that expects to be in the main app */
                    @media print {
                        body * { visibility: visible !important; }
                        .drag-handle { display: none !important; }
                    }
                </style>
            </head>
            <body>
                <div id="printable-content" class="iv4-document-container">
                    ${documentContent}
                </div>
            </body>
            </html>
        `);
        doc.close();

        // 3. Print execution
        const printDocument = () => {
            iframe.contentWindow?.focus();
            iframe.contentWindow?.print();

            // Cleanup after print dialog closes (approximate)
            setTimeout(() => {
                if (document.body.contains(iframe)) {
                    document.body.removeChild(iframe);
                }
            }, 3000);
        };

        // Wait for potential images/fonts to load
        setTimeout(printDocument, 1000);
    }
  };

  // --- AI EDIT FEATURE ---
  const handleAIEdit = async () => {
      if (!aiEditPrompt.trim()) return;
      setIsAIEditing(true);
      setErrorMsg(null);
      try {
          const currentHTML = editorRef.current?.innerHTML || documentContent;
          const newContent = await GeminiService.editDocumentFragment(currentHTML, aiEditPrompt);
          setDocumentContent(newContent);
          if (editorRef.current) editorRef.current.innerHTML = newContent;
          setShowAIEditModal(false);
          setAiEditPrompt('');
      } catch (error: any) {
          setErrorMsg(error.message);
          // Close modal to show error on main screen or show inside modal?
          // Let's show alert for now inside the modal logic
          alert(`Erro: ${error.message}`); 
      } finally {
          setIsAIEditing(false);
      }
  };

  // --- UI HELPERS ---
  const addNewPage = () => {
      if (editorRef.current) {
          const newPage = document.createElement('div');
          newPage.className = 'page';
          newPage.innerHTML = '<p><br/></p>';
          editorRef.current.appendChild(newPage);
          setDocumentContent(editorRef.current.innerHTML);
          setTimeout(() => newPage.scrollIntoView({ behavior: 'smooth' }), 100);
      }
  };

  const insertTextBox = () => {
      const activePage = document.querySelector('.page:hover') || document.querySelector('.page');
      if (!activePage) { return; } // Removed Alert

      const textBoxHTML = `
        <div class="draggable-box" style="position: absolute; left: 100px; top: 100px; min-width: 150px; z-index: 10;">
            <div class="drag-handle" contenteditable="false" style="background: #bfdbfe; height: 16px; cursor: move; border-radius: 4px 4px 0 0; display: flex; justify-content: center;">
                 <div style="width: 20px; height: 4px; background: #60a5fa; border-radius: 2px; margin-top: 6px;"></div>
            </div>
            <div class="box-content" contenteditable="true" style="padding: 10px; border: 1px solid #93c5fd; background: rgba(255,255,255,0.9); color: black;">
                Texto flutuante
            </div>
        </div>
      `;
      (activePage as HTMLElement).insertAdjacentHTML('beforeend', textBoxHTML);
      setDocumentContent(editorRef.current?.innerHTML || '');
  };

  const togglePageBorder = () => {
    const selection = window.getSelection();
    if (!selection?.rangeCount) return;
    const range = selection.getRangeAt(0);
    const page = (range.commonAncestorContainer as HTMLElement).closest('.page');
    if (page) {
         if (page.classList.contains('page-cover')) {
            page.classList.remove('page-cover');
         } else {
             page.classList.add('page-cover');
         }
    }
  };

  // --- PREVIEW / WORD EDITOR UI ---
  if (mode === 'preview') {
      return (
        <div className="fixed inset-0 z-50 bg-[#f0f0f0] flex flex-col animate-fade-in overflow-hidden">
            <style>{`
                /* Editor UI */
                .iv4-word-ribbon {
                    background: #f3f4f6;
                    border-bottom: 1px solid #d1d5db;
                }
                .ribbon-tab {
                    padding: 8px 16px;
                    font-size: 13px;
                    cursor: pointer;
                    color: #374151;
                    border-top-left-radius: 4px;
                    border-top-right-radius: 4px;
                }
                .ribbon-tab.active {
                    background: white;
                    color: #2563eb;
                    font-weight: 600;
                    border-bottom: 2px solid #2563eb;
                }
                .ribbon-group {
                    display: flex;
                    align-items: center;
                    gap: 4px;
                    padding: 0 12px;
                    border-right: 1px solid #e5e7eb;
                    height: 100%;
                }
                .ribbon-btn {
                    display: flex;
                    flex-direction: column;
                    align-items: center;
                    justify-content: center;
                    padding: 4px 8px;
                    border-radius: 4px;
                    color: #4b5563;
                    font-size: 11px;
                    gap: 2px;
                    min-width: 40px;
                }
                .ribbon-btn:hover { background: #e5e7eb; color: black; }
                .ribbon-btn-sm { padding: 4px; }

                /* Draggable Logic (Simple CSS Based, needs JS for actual move) */
                .draggable-box:active .drag-handle { cursor: grabbing; background: #60a5fa !important; }
            `}</style>

            {/* --- TOP BAR (System) --- */}
            <div className="h-10 bg-[#2b579a] flex items-center justify-between px-4 text-white shrink-0">
                <div className="flex items-center gap-4">
                    <button onClick={() => setMode('wizard')} className="hover:bg-white/20 p-1 rounded"><ArrowLeft size={16}/></button>
                    <span className="font-semibold text-sm flex items-center gap-2 max-w-[150px] md:max-w-none truncate"><FileText size={14}/> {metadata.topic || "Documento Sem Título"}</span>
                </div>
                <div className="flex items-center gap-2">
                    <button onClick={() => setShowSavedDocsModal(true)} className="p-1.5 hover:bg-white/20 rounded" title="Abrir"><FolderOpen size={16}/></button>
                    <button onClick={saveDocument} className="p-1.5 hover:bg-white/20 rounded" title="Salvar"><Save size={16}/></button>
                </div>
            </div>

            {/* --- RIBBON INTERFACE --- */}
            <div className="bg-white border-b border-gray-300 shadow-sm shrink-0 flex flex-col">
                {/* Tabs */}
                <div className="flex px-2 bg-[#f3f4f6] pt-1 overflow-x-auto">
                    <div className={`ribbon-tab whitespace-nowrap ${activeTab === 'inicio' ? 'active' : ''}`} onClick={() => setActiveTab('inicio')}>Início</div>
                    <div className={`ribbon-tab whitespace-nowrap ${activeTab === 'inserir' ? 'active' : ''}`} onClick={() => setActiveTab('inserir')}>Inserir</div>
                    <div className={`ribbon-tab whitespace-nowrap ${activeTab === 'layout' ? 'active' : ''}`} onClick={() => setActiveTab('layout')}>Leiaute</div>
                </div>

                {/* Toolbar Content */}
                <div className="h-24 flex items-center px-2 py-2 gap-2 bg-white overflow-x-auto custom-scrollbar">

                    {activeTab === 'inicio' && (
                        <>
                            <div className="ribbon-group">
                                <button className="ribbon-btn" onClick={() => executeCommand('paste')}><div className="bg-yellow-100 p-2 rounded"><FolderOpen size={20} className="text-yellow-600"/></div>Colar</button>
                            </div>
                            <div className="ribbon-group">
                                <div className="flex flex-col gap-1">
                                    <div className="flex gap-1">
                                        <select onChange={(e) => executeCommand('fontName', e.target.value)} className="h-6 text-xs border border-gray-300 rounded w-24 md:w-32">
                                            <option value="Times New Roman">Times</option>
                                            <option value="Arial">Arial</option>
                                            <option value="Calibri">Calibri</option>
                                        </select>
                                        <select onChange={(e) => executeCommand('fontSize', e.target.value)} className="h-6 text-xs border border-gray-300 rounded w-14">
                                            <option value="3">12</option>
                                            <option value="4">14</option>
                                            <option value="5">18</option>
                                            <option value="6">24</option>
                                        </select>
                                    </div>
                                    <div className="flex gap-1">
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('bold')}><Bold size={16}/></button>
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('italic')}><Italic size={16}/></button>
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('underline')}><Underline size={16}/></button>
                                    </div>
                                </div>
                            </div>
                            <div className="ribbon-group hidden md:flex">
                                <div className="flex flex-col gap-1">
                                    <div className="flex gap-1">
                                         <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('insertUnorderedList')}><List size={16}/></button>
                                         <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('insertOrderedList')}><ListOrdered size={16}/></button>
                                    </div>
                                    <div className="flex gap-1">
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('justifyLeft')}><AlignLeft size={16}/></button>
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('justifyCenter')}><AlignCenter size={16}/></button>
                                        <button className="ribbon-btn-sm hover:bg-gray-100 rounded" onClick={() => executeCommand('justifyRight')}><AlignRight size={16}/></button>
                                    </div>
                                </div>
                            </div>
                            <div className="ribbon-group">
                                <button className="ribbon-btn whitespace-nowrap" onClick={() => setShowHumanizer(true)}>
                                    <Sparkles size={20} className="text-purple-600" /> Humanizar
                                </button>
                                <button className="ribbon-btn whitespace-nowrap" onClick={() => setShowAIEditModal(true)}>
                                    <Edit3 size={20} className="text-green-600" /> Editar IA
                                </button>
                            </div>
                        </>
                    )}

                    {activeTab === 'inserir' && (
                        <>
                            <div className="ribbon-group">
                                <button className="ribbon-btn whitespace-nowrap" onClick={addNewPage}><PlusCircle size={24} className="text-blue-600"/>Nova Página</button>
                            </div>
                            <div className="ribbon-group">
                                <button className="ribbon-btn whitespace-nowrap" onClick={insertTextBox}><BoxSelect size={24} className="text-gray-600"/>Cx Texto</button>
                                <button className="ribbon-btn"><ImageIcon size={24} className="text-gray-600"/>Imagem</button>
                            </div>
                        </>
                    )}

                    {activeTab === 'layout' && (
                        <>
                             <div className="ribbon-group">
                                <button className="ribbon-btn" onClick={togglePageBorder}><Frame size={24}/>Bordas</button>
                            </div>
                            <div className="ribbon-group">
                                <button className="ribbon-btn" onClick={() => executeCommand('indent')}><Indent size={24}/>Recuar</button>
                                <button className="ribbon-btn" onClick={() => executeCommand('outdent')}><Outdent size={24}/>Avançar</button>
                            </div>
                        </>
                    )}

                    <div className="flex-grow"></div>
                    <button onClick={handleDownloadPDF} className="bg-blue-600 text-white px-3 py-2 rounded shadow hover:bg-blue-700 flex items-center gap-2 whitespace-nowrap text-sm">
                        <Download size={16}/> PDF
                    </button>
                </div>
            </div>

            {/* --- DOCUMENT EDITOR --- */}
            <div className="flex-grow overflow-y-auto bg-[#e5e5e5] p-2 md:p-8 flex justify-center relative">
                {/* AI Edit Button Floating */}
                <button 
                    onClick={() => setShowAIEditModal(true)}
                    className="absolute right-4 bottom-4 md:right-8 md:top-8 md:bottom-auto bg-green-600 text-white p-3 rounded-full shadow-lg hover:bg-green-700 transition-transform hover:scale-105 z-40 flex items-center gap-2"
                >
                    <Edit3 size={20} /> <span className="text-sm font-bold hidden md:inline">Editar com IA</span>
                </button>

                <div id="printable-content" className="iv4-document-wrapper w-full flex justify-center">
                    <div 
                        ref={editorRef}
                        className="iv4-editor outline-none iv4-document-container w-full"
                        contentEditable
                        suppressContentEditableWarning
                        onInput={(e) => setDocumentContent(e.currentTarget.innerHTML)}
                        dangerouslySetInnerHTML={{ __html: documentContent }}
                        onBlur={() => setDocumentContent(editorRef.current?.innerHTML || '')}
                    />
                </div>
            </div>

            {/* --- MODALS --- */}

            {/* AI Edit Modal */}
            {showAIEditModal && (
                <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-lg">
                        <div className="flex justify-between items-center mb-4">
                            <h3 className="font-bold text-lg flex items-center gap-2 text-gray-900"><Sparkles className="text-green-600"/> Editor Inteligente</h3>
                            <button onClick={() => setShowAIEditModal(false)}><X size={20} className="text-gray-500"/></button>
                        </div>
                        <p className="text-sm text-gray-500 mb-4">Diga o que você quer mudar no documento (Ex: "Adicione um parágrafo sobre a Guerra Fria na Introdução" ou "Mude o nome do aluno para João").</p>
                        <textarea 
                            value={aiEditPrompt}
                            onChange={(e) => setAiEditPrompt(e.target.value)}
                            className="w-full h-32 border border-gray-300 rounded-lg p-3 mb-4 focus:ring-2 focus:ring-green-500 outline-none resize-none text-black"
                            placeholder="Descreva as alterações..."
                        />
                        <button 
                            onClick={handleAIEdit}
                            disabled={isAIEditing}
                            className="w-full bg-green-600 text-white py-3 rounded-lg font-medium hover:bg-green-700 disabled:opacity-50 flex justify-center items-center gap-2"
                        >
                            {isAIEditing ? <Loader2 className="animate-spin"/> : <Send size={18}/>}
                            {isAIEditing ? 'Processando...' : 'Aplicar Alterações'}
                        </button>
                    </div>
                </div>
            )}

            {/* Saved Docs Modal */}
            {showSavedDocsModal && (
                <div className="fixed inset-0 bg-black/50 z-[60] flex items-center justify-center p-4 backdrop-blur-sm">
                    <div className="bg-white rounded-xl shadow-2xl p-6 w-full max-w-2xl max-h-[80vh] flex flex-col">
                        <div className="flex justify-between items-center mb-4 border-b pb-2">
                            <h3 className="font-bold text-lg flex items-center gap-2 text-gray-900"><FolderOpen className="text-blue-600"/> Documentos Salvos</h3>
                            <button onClick={() => setShowSavedDocsModal(false)}><X size={20} className="text-gray-500"/></button>
                        </div>

                        <div className="overflow-y-auto flex-grow">
                            {savedDocuments.length === 0 ? (
                                <p className="text-center text-gray-500 py-10">Nenhum documento salvo.</p>
                            ) : (
                                <div className="space-y-2">
                                    {savedDocuments.map(doc => (
                                        <div key={doc.id} onClick={() => loadDocument(doc)} className="flex items-center justify-between p-3 hover:bg-gray-100 rounded-lg cursor-pointer border border-gray-100">
                                            <div className="flex items-center gap-3">
                                                <div className="bg-blue-100 p-2 rounded text-blue-600"><FileText size={20}/></div>
                                                <div>
                                                    <p className="font-medium text-gray-800">{doc.title}</p>
                                                    <p className="text-xs text-gray-500">{new Date(doc.createdAt).toLocaleDateString()} às {new Date(doc.createdAt).toLocaleTimeString()}</p>
                                                </div>
                                            </div>
                                            <button onClick={(e) => deleteSavedDocument(doc.id, e)} className="p-2 text-gray-400 hover:text-red-500"><X size={18}/></button>
                                        </div>
                                    ))}
                                </div>
                            )}
                        </div>
                    </div>
                </div>
            )}

             <Humanizer 
                isOpen={showHumanizer}
                onClose={() => setShowHumanizer(false)}
                currentText={documentContent}
                onApply={(text) => {
                    setDocumentContent(text);
                    if (editorRef.current) {
                        editorRef.current.innerHTML = text;
                    }
                }}
            />
        </div>
      );
  }

  // --- WIZARD UI (CHAT) ---
  return (
    <div className="h-full flex flex-col max-w-2xl mx-auto animate-fade-in relative">
        <div className="absolute top-0 right-0 p-4">
             <button onClick={() => setShowSavedDocsModal(true)} className="flex items-center gap-2 text-indigo-600 bg-indigo-50 px-3 py-1 rounded-lg text-sm hover:bg-indigo-100">
                <FolderOpen size={16}/> Abrir Salvos
             </button>
        </div>

        <div className="flex-grow overflow-y-auto space-y-4 pb-4 custom-scrollbar">
            {messages.map((msg) => (
                <div key={msg.id} className={`flex ${msg.role === 'user' ? 'justify-end' : 'justify-start'}`}>
                    <div className={`max-w-[85%] p-4 rounded-2xl ${
                        msg.role === 'user' 
                        ? 'bg-indigo-600 text-white rounded-tr-none' 
                        : msg.role === 'system'
                        ? 'bg-red-50 dark:bg-red-900/10 text-red-600 dark:text-red-400 border border-red-100 dark:border-red-800'
                        : 'bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 text-gray-800 dark:text-gray-200 rounded-tl-none shadow-sm'
                    }`}>
                        <p className="whitespace-pre-wrap">{msg.text}</p>
                    </div>
                </div>
            ))}
            <div ref={messagesEndRef} />
        </div>

        {/* Error Banner for Wizard */}
        {errorMsg && (
             <div className="bg-red-100 dark:bg-red-900/30 text-red-800 dark:text-red-300 p-3 rounded-lg mb-2 flex items-center gap-2 text-sm border border-red-200 dark:border-red-800">
                <AlertTriangle size={16} />
                {errorMsg}
                <button onClick={() => setErrorMsg(null)} className="ml-auto"><X size={14}/></button>
             </div>
        )}

        <div className="mt-4 bg-white dark:bg-gray-800 p-2 rounded-xl border border-gray-200 dark:border-gray-700 flex flex-col gap-2 shadow-sm">
            {isReadyToGenerate && (
                <div className="px-2 py-2 bg-green-50 dark:bg-green-900/20 rounded-lg flex justify-between items-center animate-fade-in">
                    <span className="text-sm text-green-700 dark:text-green-300 flex items-center gap-2">
                        <CheckCircle size={16}/> Tudo pronto para criar o documento!
                    </span>
                    <button 
                        onClick={handleGenerateDocument}
                        disabled={isGeneratingDoc}
                        className="bg-green-600 text-white px-4 py-1.5 rounded-lg text-sm font-medium hover:bg-green-700 disabled:opacity-50 flex items-center gap-2"
                    >
                        {isGeneratingDoc ? <Loader2 className="animate-spin" size={16}/> : <FileCheck size={16}/>}
                        {isGeneratingDoc ? 'Gerando...' : 'Gerar Agora'}
                    </button>
